// 1. Get all items from the Google Sheets node
const items = $input.all();

// 2. Define the cleaning logic
const cleanedData = items
  .filter(item => {
    // REMOVE EMPTY ROWS: Only keep rows that have a Date and a Product Type
    const data = item.json;
    return data["Date"] && data["Product type"] && data["Date"].toString().trim() !== "";
  })
  .map(item => {
    const data = item.json;

    // CLEAN COMMAS & CURRENCY: Convert "₹28,000" -> 28000 (Number)
    let rawSales = data["Total sales (₹)"] ? data["Total sales (₹)"].toString() : "0";
    let cleanSales = Number(rawSales.replace(/[₹,]/g, ''));

    // CLEAN QUANTITY: Ensure "8" is a Number, not a string
    let cleanQty = Number(data["Net quantity"]) || 0;

    // RETURN CLEANED OBJECT: This creates the "Table" format n8n likes
    return {
      json: {
        ...data, // Keeps original columns (Date, Day, etc.)
        "Total sales (₹)": cleanSales, // Overwrites with pure number
        "Net quantity": cleanQty,     // Overwrites with pure number
        "IsCleaned": true              // Flag for your own tracking
      }
    };
  });

return cleanedData;

// Define the full range: 19-Mar to 1-Apr
const rangeStart = new Date(2026, 2, 19); 
const rangeEnd = new Date(2026, 3, 1);
rangeEnd.setHours(23, 59, 59);

function parseSheetDate(dateStr) {
  const months = { "Jan":0, "Feb":1, "Mar":2, "Apr":3, "May":4, "Jun":5, "Jul":6, "Aug":7, "Sep":8, "Oct":9, "Nov":10, "Dec":11 };
  const parts = dateStr.split('-');
  return new Date(parts[2], months[parts[1]], parts[0]);
}

return items.filter(item => {
  const rowDate = parseSheetDate(item.json["Date"]);
  return rowDate >= rangeStart && rowDate <= rangeEnd;
});

