let currentTotal = 0;
let previousTotal = 0;
let totalQty = 0;

// Track categories for both weeks
const currentCatMap = {}; 
const prevCatMap = {}; 
const dailyTrend = { "Monday":0, "Tuesday":0, "Wednesday":0, "Thursday":0, "Friday":0, "Saturday":0, "Sunday":0 };

// 1. Define the split date
const splitDate = new Date(2026, 2, 26); 

for (const item of items) {
  const months = { "Jan":0, "Feb":1, "Mar":2, "Apr":3, "May":4, "Jun":5, "Jul":6, "Aug":7, "Sep":8, "Oct":9, "Nov":10, "Dec":11 };
  const parts = item.json["Date"].split('-');
  const rowDate = new Date(parts[2], months[parts[1]], parts[0]);
  const sales = Number(item.json["Total sales (₹)"]) || 0;
  const qty = Number(item.json["Net quantity"]) || 0;
  const cat = item.json["Product type"];

  if (rowDate >= splitDate) {
    // --- CURRENT WEEK ---
    currentTotal += sales;
    totalQty += qty;
    currentCatMap[cat] = (currentCatMap[cat] || 0) + sales;
    const dayName = item.json["Day"];
    if (dailyTrend.hasOwnProperty(dayName)) dailyTrend[dayName] += sales;
  } else {
    // --- PREVIOUS WEEK ---
    previousTotal += sales;
    prevCatMap[cat] = (prevCatMap[cat] || 0) + sales;
  }
}

// 2. Performance Metrics & Color Logic
const isGrowthPositive = currentTotal >= previousTotal;
const growthValue = previousTotal === 0 ? 100 : ((currentTotal - previousTotal) / previousTotal * 100).toFixed(1);

const growthStatus = isGrowthPositive ? "📈 Up" : "📉 Down";
const growthColor = isGrowthPositive ? "#27ae60" : "#e74c3c"; // Green if up, Red if down

// 3. Build Category Comparison Table
let categoryRows = "";
const allCategories = Array.from(new Set([...Object.keys(currentCatMap), ...Object.keys(prevCatMap)]));
allCategories.sort((a, b) => (currentCatMap[b] || 0) - (currentCatMap[a] || 0));

const aiCategorySummary = [];

for (const cat of allCategories) {
  const curVal = currentCatMap[cat] || 0;
  const prevVal = prevCatMap[cat] || 0;

  let catChange = "New";
  if (prevVal > 0) {
    catChange = (((curVal - prevVal) / prevVal) * 100).toFixed(0) + "%";
  }

  const statusIcon = curVal >= prevVal ? "▲" : "▼";
  const statusColor = curVal >= prevVal ? "#27ae60" : "#e74c3c";

  categoryRows += `
    <tr style="border-bottom: 1px solid #eee; font-size: 13px;">
      <td style="padding: 12px 8px; color: #333;"><strong>${cat}</strong></td>
      <td style="padding: 12px 8px; text-align: right;">₹${prevVal.toLocaleString('en-IN')}</td>
      <td style="padding: 12px 8px; text-align: right; font-weight: bold;">₹${curVal.toLocaleString('en-IN')}</td>
      <td style="padding: 12px 8px; text-align: right; color: ${statusColor}; font-weight: bold;">
        ${statusIcon} ${catChange}
      </td>
    </tr>`;

  aiCategorySummary.push(`${cat}: ₹${curVal} (vs ₹${prevVal} last week)`);
}

// 4. Final Output
return [{
  json: {
    currentTotalFormatted: currentTotal.toLocaleString('en-IN'),
    previousTotalFormatted: previousTotal.toLocaleString('en-IN'),
    totalQty,
    growth: (growthValue > 0 ? "+" : "") + growthValue + "%",
    growthStatus,
    growthColor, // <--- EXPLICIT COLOR PASSED TO HTML
    isGrowthPositive,
    prevCatMap: JSON.stringify(prevCatMap),

    aiContext: `This week: ₹${currentTotal}. Last week: ₹${previousTotal}. Growth: ${growthValue}%. Details per category: ${aiCategorySummary.join(', ')}.`,

    chartData: ["Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday", "Sunday"].map(d => dailyTrend[d]).join(','),
    catLabels: JSON.stringify(allCategories),
    catValues: JSON.stringify(allCategories.map(c => currentCatMap[c] || 0)),

    categoryTableHtml: categoryRows,
    weekRange: "26-Mar-2026 to 01-Apr-2026"
  }
}];
